"use client";

import { clamp01, type RemocnTheme, useRemocnTheme } from "@/lib/remocn-ui";

export interface ProgressStyle {
  value: number;
}

export interface ProgressProps {
  value?: number;
  style?: ProgressStyle;
  width?: number;
  showLabel?: boolean;
  theme?: Partial<RemocnTheme>;
  className?: string;
}

const TRACK_HEIGHT = 12;

function clampValue(value: number): number {
  return clamp01(value / 100) * 100;
}

export function Progress({
  value = 0,
  style,
  width = 320,
  showLabel = false,
  theme: themeOverride,
  className,
}: ProgressProps) {
  const theme = useRemocnTheme(themeOverride, "light");
  const v = clampValue(style ? style.value : value);

  const track = theme.muted;
  const indicator = theme.primary;

  return (
    <div
      className={className}
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: 12,
        fontFamily:
          "var(--font-geist-sans), -apple-system, BlinkMacSystemFont, sans-serif",
      }}
    >
      {}
      <div
        style={{
          position: "relative",
          width,
          height: TRACK_HEIGHT,
          borderRadius: TRACK_HEIGHT / 2,
          background: track,
          overflow: "hidden",
        }}
      >
        <div
          style={{
            position: "absolute",
            left: 0,
            top: 0,
            bottom: 0,
            width: `${v}%`,
            borderRadius: TRACK_HEIGHT / 2,
            background: indicator,
          }}
        />
      </div>
      {showLabel && (
        <span
          style={{
            fontSize: 14,
            fontWeight: 500,
            fontVariantNumeric: "tabular-nums",
            color: theme.mutedForeground,
            minWidth: "3ch",
            textAlign: "right",
          }}
        >
          {Math.floor(v)}%
        </span>
      )}
    </div>
  );
}

"use client";

import { useCurrentFrame } from "remotion";
import type { ProgressStyle } from "@/components/remocn/progress";
import { clamp01, type EasingName, easings } from "@/lib/remocn-ui";

export interface ProgressStep {
  at: number;
  value: number;
  duration?: number;
  easing?: EasingName;
}

export const DEFAULT_DURATION = 24;

export interface ProgressTransitionOptions {
  speed?: number;
  defaultDuration?: number;
}

export function tweenProgressStyle(
  a: ProgressStyle,
  b: ProgressStyle,
  t: number,
): ProgressStyle {
  return { value: a.value + (b.value - a.value) * t };
}

export function useProgressTransition(
  steps: ProgressStep[],
  opts: ProgressTransitionOptions = {},
): ProgressStyle {
  const { speed = 1 } = opts;
  const raw = useCurrentFrame() * speed;
  return progressValueAt(steps, raw, opts);
}

export function progressValueAt(
  steps: ProgressStep[],
  raw: number,
  opts: ProgressTransitionOptions = {},
): ProgressStyle {
  const { defaultDuration = DEFAULT_DURATION } = opts;

  if (steps.length === 0) return { value: 0 };

  const first = steps[0];

  if (raw <= first.at) return { value: first.value };

  let toIndex = steps.length - 1;
  for (let i = 1; i < steps.length; i++) {
    if (steps[i].at > raw) {
      toIndex = i;
      break;
    }
  }
  const pastLast = raw >= steps[steps.length - 1].at;
  const to = pastLast ? steps[steps.length - 1] : steps[toIndex];
  const from = pastLast ? steps[steps.length - 1] : steps[toIndex - 1];

  const dur = to.duration ?? defaultDuration;
  const ease = easings[to.easing ?? "out"];
  const start = to.at - dur;
  const t = pastLast || dur <= 0 ? 1 : ease(clamp01((raw - start) / dur));
  const value = from.value + (to.value - from.value) * t;

  return { value };
}
